{"file_path": "/project/ktlint-rule-engine/src/test/kotlin/com/pinterest/ktlint/rule/engine/api/RepeatedFormatIntegrationTest.kt", "content": "package com.pinterest.ktlint.rule.engine.api

import com.pinterest.ktlint.rule.engine.core.api.ElementType
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.Test

/**
 * Integration test demonstrating a realistic scenario where multiple rules interact
 * and require multiple passes to fully format the code.
 */
class RepeatedFormatIntegrationTest {
    @Test
    fun `Given two rules that depend on each other's output, format should automatically rerun to fully correct the code`() {
        val code = Code.fromSnippet("val x = \"aaa\"")

        val actualFormattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { RuleA() },
                        RuleProvider { RuleB() },
                    ),
            ).format(code)

        // RuleA changes "a" to "b", RuleB changes "b" to "c"
        // Without repeated format: "aaa" -> "baa" (only first pass)
        // With repeated format: "aaa" -> "baa" -> "cba" -> "ccb" -> "ccc"
        assertThat(actualFormattedCode).isEqualTo("val x = \"ccc\"")
    }

    @Test
    fun `Given code that becomes fully formatted after multiple passes, no errors should remain`() {
        val code = Code.fromSnippet("val x = \"aa\"")

        val errors = mutableListOf<LintError>()
        val actualFormattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { RuleA() },
                        RuleProvider { RuleB() },
                    ),
            ).format(code) { error, corrected ->
                if (!corrected) {
                    errors.add(error)
                }
            }

        // After all passes, code should be fully formatted with no remaining errors
        assertThat(actualFormattedCode).isEqualTo("val x = \"cc\"")
        assertThat(errors).isEmpty()
    }
}

/**
 * A rule that replaces the first "a" with "b"
 */
private class RuleA : Rule(
    ruleId = RuleId("test:rule-a"),
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == ElementType.REGULAR_STRING_PART && node.text.contains("a")) {
            emit(node.startOffset, "Replace 'a' with 'b'", true)
            if (autoCorrect) {
                val newText = node.text.replaceFirst("a", "b")
                (node as LeafElement).rawReplaceWithText(newText)
            }
        }
    }
}

/**
 * A rule that replaces the first "b" with "c"
 */
private class RuleB : Rule(
    ruleId = RuleId("test:rule-b"),
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == ElementType.REGULAR_STRING_PART && node.text.contains("b")) {
            emit(node.startOffset, "Replace 'b' with 'c'", true)
            if (autoCorrect) {
                val newText = node.text.replaceFirst("b", "c")
                (node as LeafElement).rawReplaceWithText(newText)
            }
        }
    }
}
"}

