     * Fix style violations in [code] for lint errors when possible. If [code] is passed as file reference then the '.editorconfig' files on
     * the path are taken into account. For each lint violation found, the [callback] is invoked.
     *
     * @throws KtLintParseException if text is not a valid Kotlin code
     * @throws KtLintRuleException in case of internal failure caused by a bug in rule implementation
     */
    public fun format(
        code: Code,
        callback: (LintError, Boolean) -> Unit = { _, _ -> },
    ): String {
        LOGGER.debug { "Starting with formatting file '${code.fileNameOrStdin()}'" }

        val hasUTF8BOM = code.content.startsWith(UTF8_BOM)
        var currentCode = code
        var ruleExecutionContext = createRuleExecutionContext(this, currentCode)

        var tripped = false
        var mutated = false
        val errors = mutableSetOf<Pair<LintError, Boolean>>()
        val visitorProvider = VisitorProvider(ruleExecutionContext.ruleProviders)

        // Repeat format step until no more errors are found which can be auto-corrected, up to a maximum of 3 reruns
        val maxRuns = 3
        var currentRun = 0
        var wasAutoCorrected: Boolean

        do {
            currentRun++
            wasAutoCorrected = false

            LOGGER.trace { "Format run $currentRun for file '${currentCode.fileNameOrStdin()}'" }

            visitorProvider
                .visitor()
                .invoke { rule ->
                    ruleExecutionContext.executeRule(rule, true) { offset, errorMessage, canBeAutoCorrected ->
                        tripped = true
                        if (canBeAutoCorrected) {
                            mutated = true
                            wasAutoCorrected = true
                            /**
                             * Rebuild the suppression locator after each change in the AST as the offsets of the
                             * suppression hints might have changed.
                             */
                            ruleExecutionContext.rebuildSuppressionLocator()
                        }
                        val (line, col) = ruleExecutionContext.positionInTextLocator(offset)
                        errors.add(
                            Pair(
                                LintError(line, col, rule.ruleId, errorMessage, canBeAutoCorrected),
                                // It is assumed that a rule that emits that an error can be autocorrected, also
                                // does correct the error.
                                canBeAutoCorrected,
                            ),
                        )
                        // In trace mode report the violation immediately. The order in which violations are actually found might be different
                        // from the order in which they are reported. For debugging purposes it cn be helpful to know the exact order in which
                        // violations are being solved.
                        LOGGER.trace {
                            "Format violation: ${currentCode.fileNameOrStdin()}:$line:$col: $errorMessage (${rule.ruleId})" +
                                canBeAutoCorrected.ifFalse { " [cannot be autocorrected]" }
                        }
                    }
                }

            // If there were autocorrections and we haven't reached the max runs, prepare for the next run
            if (wasAutoCorrected && currentRun < maxRuns) {
                val formattedCode =
                    ruleExecutionContext
                        .rootNode
                        .text
                        .replace("\n", ruleExecutionContext.determineLineSeparator(currentCode.content))
                val codeWithBom = if (hasUTF8BOM) {
                    UTF8_BOM + formattedCode
                } else {
                    formattedCode
                }

                // Create new code instance with the formatted content
                currentCode = when {
                    currentCode.filePath != null -> Code.fromPath(currentCode.filePath!!)
                    else -> Code.fromSnippet(codeWithBom, script = currentCode.script)
                }

                // Recreate the rule execution context with the newly formatted code
                ruleExecutionContext = createRuleExecutionContext(this, currentCode)
            }
        } while (wasAutoCorrected && currentRun < maxRuns)

        // After all format passes, do a final lint pass to collect any remaining violations
        if (tripped) {
            visitorProvider
                .visitor()
                .invoke { rule ->
                    ruleExecutionContext.executeRule(
                        rule,
                        false,
                    ) { offset, errorMessage, canBeAutoCorrected ->
                        val (line, col) = ruleExecutionContext.positionInTextLocator(offset)
                        errors.add(
                            Pair(
                                LintError(line, col, rule.ruleId, errorMessage, canBeAutoCorrected),
                                // It is assumed that a rule only corrects an error after it has emitted an
                                // error and indicating that it actually can be autocorrected.
                                false,
                            ),
                        )
                    }
                }
        }

        errors
            .sortedWith { (l), (r) -> if (l.line != r.line) l.line - r.line else l.col - r.col }
            .forEach { (e, corrected) -> callback(e, corrected) }

        if (!mutated) {
            return code.content
        }

        val formattedCode =
            ruleExecutionContext
                .rootNode
                .text
                .replace("\n", ruleExecutionContext.determineLineSeparator(code.content))
        return if (hasUTF8BOM) {
            UTF8_BOM + formattedCode
        } else {
            formattedCode
        }.also {
            LOGGER.debug("Finished with formatting file '${code.fileNameOrStdin()}'")
        }
    }"}

