{"file_path": "/project/ktlint-rule-engine/src/test/kotlin/com/pinterest/ktlint/rule/engine/api/RepeatedFormatTest.kt", "content": "package com.pinterest.ktlint.rule.engine.api

import com.pinterest.ktlint.rule.engine.core.api.ElementType
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.Test

/**
 * Test that format repeats until no more errors can be auto-corrected (up to 3 times)
 */
class RepeatedFormatTest {
    @Test
    fun `Given a rule that requires multiple passes to fully format, then format should automatically repeat up to 3 times`() {
        val code = Code.fromSnippet("val x = \"aaa\"")

        var formatCallCount = 0
        val actualFormattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { 
                            MultiPassRule { formatCallCount++ }
                        },
                    ),
            ).format(code)

        // The rule replaces "a" with "b" one character at a time
        // After 3 passes: "aaa" -> "baa" -> "bba" -> "bbb"
        assertThat(actualFormattedCode).isEqualTo("val x = \"bbb\"")

        // Verify that format was called multiple times automatically
        assertThat(formatCallCount).isGreaterThan(1)
    }

    @Test
    fun `Given a rule that is fully corrected in one pass, then format should only run once`() {
        val code = Code.fromSnippet("val x = \"test\"")

        var formatCallCount = 0
        val actualFormattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { 
                            SinglePassRule { formatCallCount++ }
                        },
                    ),
            ).format(code)

        // The rule replaces "test" with "replaced" in a single pass
        assertThat(actualFormattedCode).isEqualTo("val x = \"replaced\"")

        // Verify that format was called only once
        assertThat(formatCallCount).isEqualTo(1)
    }

    @Test
    fun `Given a rule that never stabilizes, then format should stop after 3 passes`() {
        val code = Code.fromSnippet("val x = \"aaa\"")

        var formatCallCount = 0
        val actualFormattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { 
                            MultiPassRule { formatCallCount++ }
                        },
                    ),
            ).format(code)

        // Verify that format stopped after maximum of 3 passes
        assertThat(formatCallCount).isEqualTo(3)

        // After 3 passes the code should be partially corrected
        assertThat(actualFormattedCode).isEqualTo("val x = \"bbb\"")
    }
}

/**
 * A rule that requires multiple passes to fully format.
 * It replaces the first occurrence of "a" with "b" in each pass.
 */
private class MultiPassRule(
    private val onFormat: () -> Unit = {},
) : Rule(
    ruleId = RuleId("test:multi-pass"),
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == ElementType.REGULAR_STRING_PART && node.text.contains("a")) {
            onFormat()
            emit(node.startOffset, "Replace 'a' with 'b'", true)
            if (autoCorrect) {
                // Replace only the first 'a' with 'b' to force multiple passes
                val newText = node.text.replaceFirst("a", "b")
                (node as LeafElement).rawReplaceWithText(newText)
            }
        }
    }
}

/**
 * A rule that fully corrects the code in a single pass.
 */
private class SinglePassRule(
    private val onFormat: () -> Unit = {},
) : Rule(
    ruleId = RuleId("test:single-pass"),
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == ElementType.REGULAR_STRING_PART && node.text == "test") {
            onFormat()
            emit(node.startOffset, "Replace 'test' with 'replaced'", true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText("replaced")
            }
        }
    }
}
"}

